package com.example.inventory.model;
import java.util.Date;
public class SellOut { private String sellOutCode; private Date sellDate; private String shopCode; private String shopName; private Integer num; private String memo; public String getSellOutCode(){return sellOutCode;} public void setSellOutCode(String sellOutCode){this.sellOutCode=sellOutCode;} public Date getSellDate(){return sellDate;} public void setSellDate(Date sellDate){this.sellDate=sellDate;} public String getShopCode(){return shopCode;} public void setShopCode(String shopCode){this.shopCode=shopCode;} public String getShopName(){return shopName;} public void setShopName(String shopName){this.shopName=shopName;} public Integer getNum(){return num;} public void setNum(Integer num){this.num=num;} public String getMemo(){return memo;} public void setMemo(String memo){this.memo=memo;} }
